+function postProcess(tokens: Token[]): Token[] {
+  return detectPipeQueryTokens(detectArraySubscripts(combineParameterizedTypes(tokens)));
 }
+
+const pipeClauseKeywords = new Set(['AGGREGATE', 'EXTEND', 'SET', 'DROP', 'AS']);
+
+// Pipe-only keywords are identifiers in traditional BigQuery SQL. Promote them
+// only when they immediately follow a pipe so traditional queries remain unchanged.
+function detectPipeQueryTokens(tokens: Token[]): Token[] {
+  const processed = tokens.map(token => ({ ...token }));
+
+  processed.forEach((token, index) => {
+    if (token.type === TokenType.RESERVED_CLAUSE && token.text === 'FROM' && hasFollowingPipe(processed, index)) {
+      token.type = TokenType.PIPE_FROM;
+    }
+
+    if (token.type !== TokenType.PIPE_OPERATOR) {
+      return;
+    }
+
+    const clauseIndex = nextNonCommentIndex(processed, index + 1);
+    const clause = processed[clauseIndex];
+    if (!clause) {
+      return;
+    }
+    if (pipeClauseKeywords.has(clause.text)) {
+      clause.type = TokenType.RESERVED_CLAUSE;
+    }
+
+    if (clause.text === 'AGGREGATE') {
+      markAggregateGroupBy(processed, clauseIndex + 1);
+    }
+  });
+
+  return processed;
+}
+
+function hasFollowingPipe(tokens: Token[], startIndex: number): boolean {
+  let depth = 0;
+  for (let i = startIndex + 1; i < tokens.length; i++) {
+    const token = tokens[i];
+    if (token.type === TokenType.OPEN_PAREN) depth++;
+    if (token.type === TokenType.CLOSE_PAREN && --depth < 0) return false;
+    if (depth === 0 && token.type === TokenType.PIPE_OPERATOR) return true;
+    if (depth === 0 && token.type === TokenType.DELIMITER) return false;
+  }
+  return false;
+}
+
+function markAggregateGroupBy(tokens: Token[], startIndex: number) {
+  let depth = 0;
+  for (let i = startIndex; i < tokens.length; i++) {
+    const token = tokens[i];
+    if (token.type === TokenType.OPEN_PAREN) depth++;
+    if (token.type === TokenType.CLOSE_PAREN && --depth < 0) return;
+    if (depth === 0 && token.type === TokenType.PIPE_OPERATOR) return;
+    if (depth === 0 && token.type === TokenType.RESERVED_CLAUSE && token.text === 'GROUP BY') {
+      token.type = TokenType.PIPE_GROUP_BY;
+      return;
+    }
+  }
+}
+
+function nextNonCommentIndex(tokens: Token[], index: number): number {
+  while (tokens[index] && (tokens[index].type === TokenType.LINE_COMMENT || tokens[index].type === TokenType.BLOCK_COMMENT)) {
+    index++;
+  }
+  return index;
+}
